 1	import { Dropdown, DropdownItem, MenuToggle, MenuToggleElement } from '@patternfly/react-core';
 2	import * as React from 'react';
 3	import { useTranslation } from 'react-i18next';
 4	import { MetricType } from '../../model/flow-query';
 5	
 6	export interface MetricTypeDropdownProps {
 7	  selected?: string;
 8	  setMetricType: (v: MetricType) => void;
 9	  allowedTypes: MetricType[];
10	  id?: string;
11	}
12	
13	export const MetricTypeDropdown: React.FC<MetricTypeDropdownProps> = ({
14	  selected,
15	  setMetricType,
16	  id,
17	  allowedTypes
18	}) => {
19	  const { t } = useTranslation('plugin__netobserv-plugin');
20	  const [isOpen, setOpen] = React.useState(false);
21	
22	  const getMetricDisplay = React.useCallback(
23	    (metricType: MetricType): string => {
24	      switch (metricType) {
25	        case 'Bytes':
26	          return t('Bytes');
27	        case 'PktDropBytes':
28	          return t('Dropped bytes');
29	        case 'Packets':
30	          return t('Packets');
31	        case 'PktDropPackets':
32	          return t('Dropped packets');
33	        case 'DnsLatencyMs':
34	          return t('DNS latencies');
35	        case 'TimeFlowRttNs':
36	          return t('RTT');
37	        default:
38	          throw new Error('getMetricDisplay called with invalid metricType: ' + metricType);
39	      }
40	    },
41	    [t]
42	  );
43	
44	  return (
45	    <Dropdown
46	      data-test={id}
47	      id={id}
48	      isOpen={isOpen}
49	      popperProps={{
50	        position: 'right'
51	      }}
52	      toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
53	        <MenuToggle
54	          ref={toggleRef}
55	          data-test={`${id}-dropdown`}
56	          id={`${id}-dropdown`}
57	          isExpanded={isOpen}
58	          onClick={() => setOpen(!isOpen)}
59	          onBlur={() => setTimeout(() => setOpen(false), 500)}
60	        >
61	          {getMetricDisplay(selected as MetricType)}
62	        </MenuToggle>
63	      )}
64	    >
65	      {allowedTypes.map(v => (
66	        <DropdownItem
67	          data-test={v}
68	          id={v}
69	          key={v}
70	          onClick={() => {
71	            setOpen(false);
72	            setMetricType(v);
73	          }}
74	        >
75	          {getMetricDisplay(v)}
76	        </DropdownItem>
77	      ))}
78	    </Dropdown>
79	  );
80	};
81	
82	export default MetricTypeDropdown;

