 1	import { act, fireEvent, render, screen, waitFor } from '@testing-library/react';
 2	import userEvent from '@testing-library/user-event';
 3	import * as React from 'react';
 4	
 5	import { MetricType } from '../../../model/flow-query';
 6	import { MetricTypeDropdown } from '../metric-type-dropdown';
 7	
 8	describe('<MetricDropdown />', () => {
 9	  const props = {
10	    allowedTypes: ['Bytes', 'Packets'] as MetricType[],
11	    selected: 'Bytes',
12	    setMetricType: jest.fn(),
13	    id: 'metric'
14	  };
15	
16	  it('should render component', async () => {
17	    render(<MetricTypeDropdown {...props} />);
18	    expect(screen.getByRole('button')).toHaveAttribute('id', 'metric-dropdown');
19	  });
20	
21	  it('should open and close', async () => {
22	    const { container } = render(<MetricTypeDropdown {...props} />);
23	
24	    await act(async () => {
25	      fireEvent.click(container.querySelector('#metric-dropdown')!);
26	    });
27	    await waitFor(() => {
28	      expect(document.body.querySelectorAll('li').length).toBeGreaterThan(0);
29	    });
30	
31	    await act(async () => {
32	      fireEvent.click(container.querySelector('#metric-dropdown')!);
33	    });
34	
35	    expect(props.setMetricType).toHaveBeenCalledTimes(0);
36	  });
37	
38	  it('should refresh on select', async () => {
39	    const user = userEvent.setup();
40	    const { container } = render(<MetricTypeDropdown {...props} />);
41	
42	    await act(async () => {
43	      fireEvent.click(container.querySelector('#metric-dropdown')!);
44	    });
45	    await waitFor(() => expect(document.querySelector('#Packets')).toBeTruthy());
46	
47	    await user.click(document.querySelector('#Packets')!);
48	    expect(props.setMetricType).toHaveBeenCalledWith('Packets');
49	
50	    await act(async () => {
51	      fireEvent.click(container.querySelector('#metric-dropdown')!);
52	    });
53	    await waitFor(() => expect(document.querySelector('#Bytes')).toBeTruthy());
54	
55	    await user.click(document.querySelector('#Bytes')!);
56	
57	    expect(props.setMetricType).toHaveBeenCalledTimes(2);
58	    expect(props.setMetricType).toHaveBeenCalledWith('Bytes');
59	  });
60	});

